const config   = $('Dynasty Config').item.json;
const health   = $('Daily Brief: Health Check').item.json;
const stats    = $('Daily Brief: Lead Stats').item.json;
const capital  = $('Daily Brief: Capital Available').item.json;
const deployed = $('Daily Brief: Capital Deployed').item.json;
const date = new Date().toLocaleDateString('en-US',{ weekday:'long', year:'numeric', month:'long', day:'numeric', timeZone:'America/New_York' });
return [{ json: {
  date,
  apiStatus:        health?.ok ? 'ONLINE ✅' : 'OFFLINE ⚠️',
  totalLeads:       stats?.total ?? 'N/A',
  hotLeads:         stats?.by_status?.Hot ?? 0,
  qualifiedLeads:   stats?.by_status?.Qualified ?? 0,
  gradeALeads:      stats?.by_grade?.A ?? 0,
  availableCapital: capital?.total_available != null ? `$${Number(capital.total_available).toLocaleString()}` : 'N/A',
  deployedCapital:  deployed?.total_deployed_allocations != null ? `$${Number(deployed.total_deployed_allocations).toLocaleString()}` : 'N/A',
  byStatus:         stats?.by_status ?? {},
}}];

const content = $json?.message?.content;
if (content) return [{ json: { aiText: content, aiError: false } }];
try {
  const c = $('Daily Brief: Compile').item.json;
  return [{ json: {
    aiText: `Dynasty OS Daily Brief — ${c.date || new Date().toDateString()}\n• API: ${c.apiStatus || 'N/A'}\n• Hot Leads: ${c.hotLeads || 0} | Grade A: ${c.gradeALeads || 0}\n• Available Capital: ${c.availableCapital || 'N/A'}\n• Deployed Capital: ${c.deployedCapital || 'N/A'}\n\n⚠️ AI summary unavailable — raw data shown.`,
    aiError: true
  }}];
} catch(e) {
  return [{ json: { aiText: 'Dynasty OS Daily Brief: AI summary unavailable. Check PropertyOS dashboard.', aiError: true } }];
}

const health = $json;
const body = $('Deal Intake: Webhook').item.json.body ?? $('Deal Intake: Webhook').item.json;
const apiOk = health?.ok === true && !health?.error;
return [{ json: { ...body, _apiOk: apiOk, _apiError: health?.error || null } }];

const body = items[0].json.body ?? items[0].json;
const required = ['purchase_price','repair_budget','arv','address'];
const missing  = required.filter(f => body[f] == null || body[f] === '');
if (missing.length) throw new Error(`Missing required fields: ${missing.join(', ')}`);
const pp  = Number(body.purchase_price);
const arv = Number(body.arv);
const rb  = Number(body.repair_budget) || 0;
if (pp  <= 0) throw new Error('purchase_price must be a positive number');
if (arv <= 0) throw new Error('arv must be a positive number');
if (arv <  pp) throw new Error('ARV cannot be less than purchase_price — check your numbers');
return [{ json: { ...body, purchase_price: pp, repair_budget: rb, arv,
  closing_costs:  Number(body.closing_costs)  || 0,
  holding_costs:  Number(body.holding_costs)  || 0,
  selling_costs:  Number(body.selling_costs)  || 0,
}}];

const validated = $('Deal Intake: Validate').item.json;
const lookupResult = $json;
const existing = lookupResult?.properties?.[0];
if (existing?.id) {
  return [{ json: { ...validated, property_id: existing.id, property_source: 'existing', need_create: false } }];
}
const code = (validated.address || 'PROP-' + Date.now())
  .replace(/[^a-zA-Z0-9]/g, '')
  .substring(0, 20)
  .toUpperCase() || ('PROP' + Date.now().toString().slice(-8));
const addrParts = (validated.address || '').split(',');
return [{ json: {
  ...validated,
  property_id: null,
  property_source: 'new',
  need_create: true,
  _create_body: {
    property_code: code,
    address: validated.address || '',
    city: addrParts[1]?.trim() || 'Unknown',
    state: addrParts[2]?.trim()?.split(' ')[0] || 'GA',
    acquisition_price: validated.purchase_price || null,
    estimated_arv: validated.arv || null,
    status: 'planning'
  }
} }];

const validated = $('Deal Intake: Validate').item.json;
// $json is either the new property record (has .id) or the prop-logic output (has .property_id)
const property_id = $json.id || $json.property_id || null;
const property_source = $json.id ? 'created' : ($json.property_source || 'existing');
return [{ json: { ...validated, property_id, property_source } }];

